                // Try both possibilities and pick the best
                long tempXorA = xorA ^ nums[i];
                long tempXorC = xorC ^ nums[i];
                if (xorA + (andB != 0 ? andB : 0) + tempXorC > tempXorA + (andB != 0 ? andB : 0) + xorC) {
