```java
public static long solve(long[] nums) {
    int n = nums.length;
    long maxSum = 0;

    // Iterate all possible ways to split into A, B, C
    // A is from 0 to i-1, B is from i to j-1, C is from j to n-1
    for (int i = 0; i <= n; i++) {
        for (int j = i; j <= n; j++) {
            long xorA = 0;
            long andB = (1L << 32) - 1; // Initialize with all bits set for AND
            long xorC = 0;

            // Compute XOR for A (0..i-1)
            for (int k = 0; k < i; k++) {
                xorA ^= nums[k];
            }

            // Compute AND for B (i..j-1)
            boolean emptyB = true;
            for (int k = i; k < j; k++) {
                andB &= nums[k];
                emptyB = false;
            }
            if (emptyB) {
                andB = 0;
            }

            // Compute XOR for C (j..n-1)
            for (int k = j; k < n; k++) {
                xorC ^= nums[k];
            }

            long currentSum = xorA + andB + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
